"use client";

import { useEffect, useMemo, useState } from "react";
import { useParams, useRouter } from "next/navigation";
import { Button, Card, CardBody, Divider, Spinner, Tabs, Tab } from "@nextui-org/react";
import { ArrowLeft, Printer, FileText, Download, Save, ArrowRight, CheckCircle, RefreshCw, User } from "lucide-react";
import jsPDF from 'jspdf';
import type { WooCommerceProduct } from "@/types/woocommerce";
import { fetchProductById } from "@/lib/woocommerce";

export function ProductDetailClient() {
  const router = useRouter();
  const params = useParams<{ id: string }>();
  const [product, setProduct] = useState<WooCommerceProduct | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const id = Number(params.id);
    if (!Number.isFinite(id)) {
      setError("Invalid product id");
      setLoading(false);
      return;
    }

    let isMounted = true;
    setLoading(true);
    fetchProductById(id)
      .then((p) => {
        if (!isMounted) return;
        setProduct(p);
        setError(null);
      })
      .catch((e) => {
        if (!isMounted) return;
        setError(e instanceof Error ? e.message : "Failed to load product");
        setProduct(null);
      })
      .finally(() => {
        if (!isMounted) return;
        setLoading(false);
      });

    return () => {
      isMounted = false;
    };
  }, [params.id]);

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <Spinner size="lg" color="danger" />
      </div>
    );
  }

  if (error || !product) {
    return (
      <div className="min-h-screen bg-gray-50 p-6">
        <div className="max-w-3xl mx-auto">
          <Button variant="flat" startContent={<ArrowLeft className="w-4 h-4" />} onClick={() => router.back()}>
            Back
          </Button>
          <div className="mt-6 bg-white rounded-xl border border-gray-200 p-6">
            <h1 className="text-xl font-bold text-gray-900">Couldn’t load product</h1>
            <p className="text-gray-600 mt-2">{error ?? "Unknown error"}</p>
          </div>
        </div>
      </div>
    );
  }

  const generatePDF = () => {
    if (!product) return;

    // Create a simple text content for the PDF
    const pdfContent = `
PRODUCT CONFIGURATION
==================

Product Name: ${product.name}
SKU: ${product.sku || 'N/A'}

SPECIFICATIONS
==============

${product.weight ? `Weight: ${product.weight} kg` : ''}
${(product.dimensions.length || product.dimensions.width || product.dimensions.height) ? 
  `Dimensions: ${product.dimensions.length ? product.dimensions.length + 'L' : ''}${product.dimensions.width ? ' × ' + product.dimensions.width + 'W' : ''}${product.dimensions.height ? ' × ' + product.dimensions.height + 'H' : ''}` : ''}
${product.price ? `Power: ${product.price} kW` : ''}

${product.attributes && product.attributes.length > 0 ? 
  product.attributes
    .filter(attr => attr.visible && attr.options.length > 0)
    .map(attr => `${attr.name.charAt(0).toUpperCase() + attr.name.slice(1)}: ${attr.options.join(', ')}`)
    .join('\n') : ''
}

CONFIGURATION OPTIONS
===================

General Configuration:
- European CE Certification: EU Declaration of Conformity
- CIS Certification: CIS Certification

Electrical Configuration:
- [To be configured by user]

Mechanical Configuration:
- [To be configured by user]

Enclosures & Tanks:
- [To be configured by user]

Generated on: ${new Date().toLocaleDateString()}
    `.trim();

    // Create a blob and download as text file (simplified approach)
    const blob = new Blob([pdfContent], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${product.name.replace(/[^a-z0-9]/gi, '_').toLowerCase()}_configuration.txt`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Black Header */}
      <div className="w-full bg-black">
        <div className="w-full mx-auto px-6 sm:px-8 lg:px-10 py-4">
          <div className="flex items-center justify-between datasheet-print-hide">
            <Button variant="flat" startContent={<ArrowLeft className="w-4 h-4" />} onClick={() => router.back()} className="text-white border-white/20 flex items-center gap-2 hover:text-[#DA0018]">
              Back
            </Button>
            <img 
              src="/tehnolink-logo.png" 
              alt="Tehnolink Logo" 
              className="h-8 w-auto"
            />
            <Button variant="flat" startContent={<User className="w-4 h-4" />} onClick={() => {}} className="text-white border-white/20 flex items-center gap-2 hover:text-[#DA0018]">
              Log in
            </Button>
          </div>
        </div>
      </div>

      <div className="w-full mx-auto px-6 sm:px-8 lg:px-10 py-6">

        <div className="datasheet mt-6">
          <div className="grid grid-cols-1 xl:grid-cols-[1.1fr_2fr] gap-8 items-stretch">
            {/* Left: product image + basic actions */}
            <div className="flex flex-col gap-4 justify-between pr-4 h-full">
              <div>
                <div className="flex items-center justify-between mb-4 pr-4">
                  <h1 className="text-2xl font-bold text-gray-900">{product.name}</h1>
                  <div className="flex gap-3">
                    <Button
                      size="sm"
                      variant="flat"
                      className="bg-gray-200 text-gray-800 rounded-[50px] px-4 py-2 h-10 focus:ring-0 focus:outline-none hover:bg-gray-300 flex items-center justify-center shadow-lg"
                      startContent={<FileText className="w-4 h-4" />}
                    >
                      Specification
                    </Button>
                    <Button
                      size="sm"
                      variant="flat"
                      className="bg-gray-200 text-gray-800 rounded-[50px] px-4 py-2 h-10 focus:ring-0 focus:outline-none hover:bg-gray-300 flex items-center justify-center shadow-lg"
                      startContent={<Download className="w-4 h-4" />}
                    >
                      Documentation
                    </Button>
                  </div>
                </div>
              </div>

              {product.images?.[0]?.src ? (
                <Card className="shadow-none overflow-hidden bg-transparent border-0">
                  <CardBody className="p-0 flex items-center">
                    <img
                      src={product.images[0].src}
                      alt={product.images[0].alt || product.name}
                      className="w-full h-64 object-cover rounded-[10px]"
                    />
                  </CardBody>
                </Card>
              ) : null}

              {/* Product Specifications */}
              <div className="mt-0">               
                <div className="border border-gray-200 overflow-hidden">
                  <table className="w-full">
                    <tbody>
                      {product.sku && (
                        <tr className="border-b border-gray-200">
                          <td className="px-3 py-2 text-sm text-gray-600 bg-gray-50 w-1/2">SKU:</td>
                          <td className="px-3 py-2 text-sm font-bold text-gray-900 bg-white w-1/2">{product.sku}</td>
                        </tr>
                      )}
                      
                      {product.weight && (
                        <tr className="border-b border-gray-200">
                          <td className="px-3 py-2 text-sm text-gray-600 bg-gray-50 w-1/2">Weight:</td>
                          <td className="px-3 py-2 text-sm font-bold text-gray-900 bg-white w-1/2">{product.weight} kg</td>
                        </tr>
                      )}
                      
                      {(product.dimensions.length || product.dimensions.width || product.dimensions.height) && (
                        <tr className="border-b border-gray-200">
                          <td className="px-3 py-2 text-sm text-gray-600 bg-gray-50 w-1/2">Dimensions:</td>
                          <td className="px-3 py-2 text-sm font-bold text-gray-900 bg-white w-1/2">
                            {product.dimensions.length && `${product.dimensions.length}L`}
                            {product.dimensions.width && ` × ${product.dimensions.width}W`}
                            {product.dimensions.height && ` × ${product.dimensions.height}H`}
                          </td>
                        </tr>
                      )}
                      
                      {product.price && (
                        <tr className="border-b border-gray-200">
                          <td className="px-3 py-2 text-sm text-gray-600 bg-gray-50 w-1/2">Power:</td>
                          <td className="px-3 py-2 text-sm font-bold text-gray-900 bg-white w-1/2">{product.price} kW</td>
                        </tr>
                      )}

                      {product.attributes && product.attributes.length > 0 && (
                        product.attributes
                          .filter(attr => attr.visible && attr.options.length > 0)
                          .map((attribute) => (
                            <tr key={attribute.id} className="border-b border-gray-200 last:border-b-0">
                              <td className="px-3 py-2 text-sm text-gray-600 bg-gray-50 w-1/2 capitalize">{attribute.name}:</td>
                              <td className="px-3 py-2 text-sm font-bold text-gray-900 bg-white w-1/2">
                                {attribute.options.join(', ')}
                              </td>
                            </tr>
                          ))
                      )}
                    </tbody>
                  </table>
                </div>
              </div>

            </div>
            <div className="px-6 py-5 bg-white rounded-lg h-full shadow-lg">
              <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-3">
                  <div>
                    <h2 className="text-xl font-semibold text-gray-900">Configure your own</h2>
                  </div>
                  <Button
                    size="sm"
                    variant="flat"
                    className="bg-gray-200 text-gray-800 rounded-[50px] px-4 py-2 h-10 focus:ring-0 focus:outline-none hover:bg-gray-300 flex items-center justify-center shadow-lg"
                    startContent={<RefreshCw className="w-4 h-4" />}
                  >
                    Start over
                  </Button>
                  <Button
                    size="sm"
                    variant="flat"
                    className="bg-gray-200 text-gray-800 rounded-[50px] px-4 py-2 h-10 focus:ring-0 focus:outline-none hover:bg-gray-300 flex items-center justify-center shadow-lg"
                    startContent={<ArrowRight className="w-4 h-4" />}
                  >
                    Next
                  </Button>
                </div>
                <Button
                  size="sm"
                  variant="flat"
                  className="bg-gray-200 text-gray-800 rounded-[50px] px-4 py-2 pl-6 h-10 focus:ring-0 focus:outline-none hover:bg-gray-300 flex items-center justify-center shadow-lg"
                  startContent={<Save className="w-4 h-4" />}
                  onClick={() => generatePDF()}
                >
                  Save configuration
                </Button>
              </div>

              <div className="w-full block mt-5">
              <Tabs
                aria-label="Configuration steps"
                color="primary"
                variant="underlined"
                fullWidth
                classNames={{
                  base: "w-full",
                  tabList:
                    "w-full border border-gray-300 rounded-[50px] overflow-hidden flex bg-white gap-0",
                  tab: "flex-1 px-4 h-10 text-sm font-semibold text-gray-700 data-[selected=true]:bg-[#da0018] data-[selected=true]:text-white rounded-none text-center focus:outline-none focus:ring-0 flex items-center justify-center border-r border-gray-300 last:border-r-0",
                  cursor: "hidden",
                }}
              >
                <Tab key="general" title="General">
                  <div className="mt-4 space-y-5">
                    <div>
                      <p className="text-xs font-semibold text-gray-700 mb-2">European CE Certification</p>
                      <div className="flex gap-3">
                        <Button
                          size="sm"
                          variant="flat"
                          className="bg-gray-200 text-gray-800 rounded-[50px] px-4 py-2 h-10 focus:ring-0 focus:outline-none hover:bg-gray-300 flex items-center justify-center shadow-lg"
                          startContent={<CheckCircle className="w-4 h-4" />}
                        >
                          EU Declaration of Conformity
                        </Button>
                      </div>
                    </div>

                    <div>
                      <p className="text-xs font-semibold text-gray-700 mb-2">CIS Certification</p>
                      <div className="flex gap-3">
                        <Button
                          size="sm"
                          variant="flat"
                          className="bg-gray-200 text-gray-800 rounded-[50px] px-4 py-2 h-10 focus:ring-0 focus:outline-none hover:bg-gray-300 flex items-center justify-center shadow-lg"
                          startContent={<CheckCircle className="w-4 h-4" />}
                        >
                          CIS Certification
                        </Button>
                      </div>
                    </div>
                  </div>
                </Tab>

                <Tab key="electrical" title="Electrical">
                  <div className="mt-4 text-sm text-gray-700">
                    Electrical configuration options will be shown here (voltage, frequency, connections, etc.).
                  </div>
                </Tab>

                <Tab key="mechanical" title="Mechanical">
                  <div className="mt-4 text-sm text-gray-700">
                    Mechanical options like enclosures, mounting, and sound attenuation can be configured here.
                  </div>
                </Tab>

                <Tab key="enclosures" title="Enclosures & Tanks">
                  <div className="mt-4 text-sm text-gray-700">
                    Options for enclosure type, tank size, and related accessories will be displayed here.
                  </div>
                </Tab>

                <Tab key="summary" title="Summary">
                  <div className="mt-4 text-sm text-gray-700">
                    A summary of your selected configuration will appear here for final review.
                  </div>
                </Tab>
              </Tabs>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}


